changeSet.sql:
drop view if exists sch_report_ea.request_task_visit cascade;
drop view if exists sch_report_ea.request_task cascade;
drop view if exists sch_report_ea.request_task_type_action_type cascade;
drop view if exists sch_report_ea.request_task_action_type cascade;
drop view if exists sch_report_ea.request_task_type cascade;
drop view if exists sch_report_ea.request_action cascade;
drop view if exists sch_report_ea.request cascade;
drop view if exists sch_report_ea.request_type cascade;
drop view if exists sch_report_ea.request_resource cascade;
drop view if exists sch_report_ea.request_note cascade;
drop view if exists sch_report_ea.au_authority_permission cascade;
drop view if exists sch_report_ea.au_authority cascade;
drop view if exists sch_report_ea.au_role cascade;
drop view if exists sch_report_ea.au_role_permission cascade;
drop view if exists sch_report_ea.account_contact cascade;
drop view if exists sch_report_ea.account_ca_external_contacts cascade;
drop view if exists sch_report_ea.account cascade;
drop view if exists sch_report_ea.verification_body_emission_trading_scheme cascade;
drop view if exists sch_report_ea.verification_body cascade;

drop view if exists sch_report_ea.account_address cascade;
drop view if exists sch_report_ea.account_target_unit cascade;
drop view if exists sch_report_ea.account_target_unit_contact cascade;
drop view if exists sch_report_ea.account_note cascade;
drop view if exists sch_report_ea.competent_authority cascade;
drop view if exists sch_report_ea.facility_data cascade;
drop view if exists sch_report_ea.facility_address cascade;
drop view if exists sch_report_ea.location cascade;
drop view if exists sch_report_ea.sector_association cascade;
drop view if exists sch_report_ea.sector_association_contact cascade;
drop view if exists sch_report_ea.sector_association_scheme cascade;
drop view if exists sch_report_ea.subsector_association cascade;
drop view if exists sch_report_ea.subsector_association_scheme cascade;
drop view if exists sch_report_ea.target_commitment cascade;
drop view if exists sch_report_ea.target_set cascade;
drop view if exists sch_report_ea.underlying_agreement cascade;

drop view if exists sch_report_ea.tpr_target_period cascade;
drop view if exists sch_report_ea.tpr_performance_account_template_data cascade;
drop view if exists sch_report_ea.tpr_account_performance_data_status cascade;
drop view if exists sch_report_ea.tpr_performance_data cascade;
drop view if exists sch_report_ea.tpr_buy_out_surplus_exclusion cascade;
drop view if exists sch_report_ea.tpr_buy_out_surplus_transaction cascade;
drop view if exists sch_report_ea.tpr_buy_out_surplus_processed_data cascade;
drop view if exists sch_report_ea.tpr_surplus cascade;
drop view if exists sch_report_ea.tpr_certification_period cascade;
drop view if exists sch_report_ea.tpr_facility_certification cascade;
drop view if exists sch_report_ea.tpr_buy_out_surplus_transaction_history cascade;
drop view if exists sch_report_ea.facility_audit cascade;

            create or replace view sch_report_ea.account as select s.* from account s where s.competent_authority = 'ENGLAND';
            create or replace view sch_report_ea.account_contact as select s.* from account_contact s where exists (select null from account a where a.id = s.account_id and a.competent_authority = 'ENGLAND');
            create or replace view sch_report_ea.account_ca_external_contacts as select s.* from account_ca_external_contacts s where s.competent_authority = 'ENGLAND';
            create or replace view sch_report_ea.au_authority as select s.* from au_authority s where s.competent_authority = 'ENGLAND' or s.verification_body_id is not null or exists (select null from account a where a.id = s.account_id and a.competent_authority = 'ENGLAND');
            create or replace view sch_report_ea.au_authority_permission as select s.* from au_authority_permission s where exists (select null from au_authority aa where aa.id = s.authority_id and (aa.competent_authority = 'ENGLAND' or aa.verification_body_id is not null or exists (select null from account a where a.id = aa.account_id and a.competent_authority = 'ENGLAND')));
            create or replace view sch_report_ea.au_role as select s.* from au_role s;
            create or replace view sch_report_ea.au_role_permission as select s.* from au_role_permission s;
           	create or replace view sch_report_ea.request_type as select rt.* from request_type rt;
            create or replace view sch_report_ea.request_resource as select rr.* from request_resource rr where rr.request_id in (select request_id from request_resource where resource_id = 'ENGLAND');
            create or replace view sch_report_ea.request_note as select rn.* from request_note rn where exists (select null from au_authority aa where aa.user_id = rn.submitter_id and aa.competent_authority = 'ENGLAND');
            create or replace view sch_report_ea.request as select id, type_id, status, creation_date, payload, submission_date, metadata, end_date from request r where exists (select null from request_resource rr where rr.request_id = r.id and rr.resource_id = 'ENGLAND');
            create or replace view sch_report_ea.request_action as select s.* from request_action s where exists (select null from request_resource rr where rr.request_id = s.request_id and rr.resource_id = 'ENGLAND');
            create or replace view sch_report_ea.request_task_type_action_type as select * from request_task_type_action_type;
            create or replace view sch_report_ea.request_task_type as select * from request_task_type;
            create or replace view sch_report_ea.request_task_action_type as select * from request_task_action_type;
            create or replace view sch_report_ea.request_task as select id, request_id, type_id, assignee, due_date, start_date, pause_date, payload, version from request_task s where exists (select null from request_resource rr where rr.request_id = s.request_id and rr.resource_id = 'ENGLAND');
            create or replace view sch_report_ea.request_task_visit as select s.* from request_task_visit s where exists (select null from request_task rt join request_resource rr on rr.request_id = rt.request_id where rt.id = s.task_id and rr.resource_id = 'ENGLAND');
            create or replace view sch_report_ea.verification_body as select s.* from verification_body s;
            create or replace view sch_report_ea.verification_body_emission_trading_scheme as select s.* from verification_body_emission_trading_scheme s;

			create or replace view sch_report_ea.account_target_unit as select s.* from account_target_unit s where exists (select null from account a where a.id = s.id and a.competent_authority = 'ENGLAND');
			create or replace view sch_report_ea.account_target_unit_contact as select s.* from account_target_unit_contact s where exists (select null from account a where a.id = s.account_target_unit_id and a.competent_authority = 'ENGLAND');
            create or replace view sch_report_ea.account_note as select an.* from account_note an where exists (select null from au_authority aa where aa.user_id = an.submitter_id and aa.competent_authority = 'ENGLAND');
            create or replace view sch_report_ea.account_address as select s.* from account_address s where exists (select null from account a inner join account_target_unit atu on a.id = atu.id where atu.address_id = s.id and a.competent_authority = 'ENGLAND');
			create or replace view sch_report_ea.competent_authority as select s.* from competent_authority s;
			create or replace view sch_report_ea.facility_data as select s.* from facility_data s where exists (select null from account a where a.id = s.account_id and a.competent_authority = 'ENGLAND');
			create or replace view sch_report_ea.facility_address as select s.* from facility_address s where exists (select null from account a inner join facility_data fd on a.id = fd.account_id where fd.address_id = s.id and a.competent_authority = 'ENGLAND');
			create or replace view sch_report_ea.sector_association as select s.* from sector_association s where s.competent_authority = 'ENGLAND';
			create or replace view sch_report_ea.sector_association_contact as select s.* from sector_association_contact s where exists (select null from sector_association a where a.sector_association_contact_id = s.id and a.competent_authority = 'ENGLAND');
			create or replace view sch_report_ea.location as select s.* from location s where exists (select null from sector_association a where a.location_id = s.id and a.competent_authority = 'ENGLAND');
			create or replace view sch_report_ea.sector_association_scheme as select s.* from sector_association_scheme s where exists (select null from sector_association a where a.id = s.sector_association_id and a.competent_authority = 'ENGLAND');
			create or replace view sch_report_ea.subsector_association as select s.* from subsector_association s where exists (select null from sector_association a where a.id = s.sector_association_id and a.competent_authority = 'ENGLAND');
			create or replace view sch_report_ea.subsector_association_scheme as select s.* from subsector_association_scheme s where exists (select null from sector_association a inner join subsector_association sa on a.id = sa.sector_association_id where sa.id = s.subsector_association_id and a.competent_authority = 'ENGLAND');
			create or replace view sch_report_ea.target_set as select s.* from target_set s where exists (select null from sector_association a inner join sector_association_scheme sas on a.id = sas.sector_association_id where sas.target_set_id = s.id and a.competent_authority = 'ENGLAND') or exists (select null from sector_association sa join subsector_association ssa on sa.id = ssa.sector_association_id join subsector_association_scheme sas on ssa.id = sas.subsector_association_id where sa.competent_authority = 'ENGLAND' and s.id = sas.target_set_id);
			create or replace view sch_report_ea.target_commitment as select s.* from target_commitment s where exists (select null from sector_association a inner join sector_association_scheme sas on a.id = sas.sector_association_id inner join target_set ts on sas.target_set_id = ts.id where sas.target_set_id = s.target_set_id and a.competent_authority = 'ENGLAND') or exists (select null from sector_association sa join subsector_association ssa on sa.id = ssa.sector_association_id join subsector_association_scheme sas on ssa.id = sas.subsector_association_id join target_set ts on sas.target_set_id = ts.id where sa.competent_authority = 'ENGLAND' and s.target_set_id = ts.id);
			create or replace view sch_report_ea.underlying_agreement as select s.* from underlying_agreement s where exists (select null from account a where a.id = s.account_id and a.competent_authority = 'ENGLAND');

        	create or replace view sch_report_ea.tpr_target_period as select tpr.* from tpr_target_period tpr;
            create or replace view sch_report_ea.tpr_performance_account_template_data as select tpatd.* from tpr_performance_account_template_data tpatd where exists (select null from account a where a.id = tpatd.account_id and a.competent_authority = 'ENGLAND');
        	create or replace view sch_report_ea.tpr_account_performance_data_status as select apds.* from tpr_account_performance_data_status apds where exists (select null from account a where a.id = apds.account_id and a.competent_authority = 'ENGLAND');
        	create or replace view sch_report_ea.tpr_performance_data as select tpd.* from tpr_performance_data tpd where exists (select null from account a where a.id = tpd.account_id and a.competent_authority = 'ENGLAND');
        	create or replace view sch_report_ea.tpr_buy_out_surplus_exclusion as select tbose.* from tpr_buy_out_surplus_exclusion tbose where exists (select null from account a where a.id = tbose.account_id and a.competent_authority = 'ENGLAND');
        	create or replace view sch_report_ea.tpr_buy_out_surplus_transaction as select tbos.* from tpr_buy_out_surplus_transaction tbos where exists (select null from account a, tpr_performance_data tpd where tpd.id = tbos.performance_data_id and a.id = tpd.account_id and a.competent_authority = 'ENGLAND');
            create or replace view sch_report_ea.tpr_buy_out_surplus_processed_data as select tbosp.* from tpr_buy_out_surplus_processed_data tbosp where exists (select null from account a, tpr_performance_data tpd where tpd.id = tbosp.performance_data_id and a.id = tpd.account_id and a.competent_authority = 'ENGLAND');
        	create or replace view sch_report_ea.tpr_surplus as select ts.* from tpr_surplus ts where exists (select null from account a where a.id = ts.account_id and a.competent_authority = 'ENGLAND');
            create or replace view sch_report_ea.tpr_certification_period as select cp.* from tpr_certification_period cp;
            create or replace view sch_report_ea.tpr_facility_certification as select fc.* from tpr_facility_certification fc where exists (select null from facility_data fd join account a on fd.account_id = a.id where fc.facility_id = fd.id and a.competent_authority = 'ENGLAND');
            create or replace view sch_report_ea.tpr_buy_out_surplus_transaction_history as select tbosh.* from tpr_buy_out_surplus_transaction_history tbosh  where exists (select null from account a, tpr_performance_data tpd, tpr_buy_out_surplus_transaction tbos where tbosh.buy_out_surplus_transaction_id = tbos.id and tpd.id = tbos.performance_data_id and a.id = tpd.account_id and a.competent_authority = 'ENGLAND');
            create or replace view sch_report_ea.facility_audit as select fa.* from facility_audit fa where exists (select null from account a inner join facility_data fd on a.id = fd.account_id where fa.facility_id = fd.id and a.competent_authority = 'ENGLAND');
